/**
 * Workflow discovery for the leader-key Workflow group.
 *
 * A workflow is a directory under .pi/chains/ containing contract.md and a
 * *.chain.json (generated by the /wf planner). Kept in plain JS so it can be
 * unit-tested with node --test.
 */

import { existsSync, readFileSync, readdirSync } from "node:fs";
import { join } from "node:path";

/**
 * Scan a chains directory for workflow folders.
 * @param {string} chainsDir absolute path to .pi/chains
 * @returns {Array<{ name: string, dir: string, description?: string }>}
 */
export function discoverWorkflows(chainsDir) {
	if (!existsSync(chainsDir)) return [];
	const workflows = [];
	for (const entry of readdirSync(chainsDir, { withFileTypes: true })) {
		if (!entry.isDirectory()) continue;
		const dir = join(chainsDir, entry.name);
		const files = readdirSync(dir);
		if (!files.includes("contract.md")) continue;
		const chainFile = files.find((f) => f.endsWith(".chain.json"));
		if (!chainFile) continue;
		let parsed;
		try {
			parsed = JSON.parse(readFileSync(join(dir, chainFile), "utf8"));
		} catch {
			// unparseable chain.json — pi-subagents would reject it at discovery,
			// so /run-chain would fail; skip it here too
			continue;
		}
		const name = typeof parsed.name === "string" && parsed.name ? parsed.name : entry.name;
		const description = typeof parsed.description === "string" ? parsed.description : undefined;
		workflows.push({ name, dir, description });
	}
	return workflows.sort((a, b) => a.name.localeCompare(b.name));
}
